params.rawScript:
env {
  parallelism = 8
  job.mode = "BATCH"
  job.name = "hive2doris"
}

source {
  Hive {
    plugin_output = hive_source
    table_name = "ad_monitor.huan_ad_monitor_impression_log_orc"
    metastore_uri = "thrift://ali-odp-test-01:9083"
    read_partitions = ["dt=2025-05-15"]
    hive_site_path = "/etc/hive/conf/hive-site.xml"
    kerberos_principal = "ad_monitor"
    kerberos_keytab_path = "/hwdata/ad_monitor.keytab"
    krb5_path = "/etc/krb5.conf"
    hive.hadoop.conf-path = "/etc/hadoop/conf"
    hive.hadoop.conf = {
        bucket="oss://huan-bigdata-test.oss-cn-shanghai-internal.aliyuncs.com"
    }
  }
}

sink {
  Doris {
    plugin_input = hive_source
    fenodes = "ali-doris-fe-test-01:8030"
    username = "root"
    password = "P@ssw0rd"
    database = "ad_monitor"
    table = "huan_ad_monitor_impression_log_orc"
    sink.label-prefix = "seatunnel-batch"
    doris.batch.size = "102400"
    data_save_mode = "CUSTOM_PROCESSING"
    custom_sql ="delete from ad_monitor.huan_ad_monitor_impression_log_orc where dt = '2025-05-15'"
    doris.config {
      format = "json"
      read_json_by_line = "true"
    }
  }
}
